#!/bin/bash

# Codestral Demo Workflow Script
# This script demonstrates automated interactions with Codestral
# Run with: ./examples/scripts/demo-workflow.sh

echo "🚀 Codestral Demo Workflow"
echo "=========================="
echo ""

# Check if codestral is available
if ! command -v codestral &> /dev/null; then
    echo "❌ Codestral not found. Please install it first:"
    echo "   npm install -g codestral"
    exit 1
fi

echo "✅ Codestral found"
echo ""

# Create a demo project directory
DEMO_DIR="codestral-demo-$(date +%Y%m%d-%H%M%S)"
mkdir -p "$DEMO_DIR"
cd "$DEMO_DIR"

echo "📁 Created demo directory: $DEMO_DIR"
echo ""

# Create some sample files for demonstration
cat > app.js << 'EOF'
// Sample Node.js application
const express = require('express');
const app = express();

app.get('/', (req, res) => {
    res.send('Hello World!');
});

// TODO: Add error handling
// TODO: Add authentication
// FIXME: This endpoint is not secure
app.get('/admin', (req, res) => {
    res.json({ users: ['admin', 'user1', 'user2'] });
});

app.listen(3000, () => {
    console.log('Server running on port 3000');
});
EOF

cat > package.json << 'EOF'
{
  "name": "demo-app",
  "version": "1.0.0",
  "description": "Demo application for Codestral",
  "main": "app.js",
  "scripts": {
    "start": "node app.js",
    "test": "echo \"Error: no test specified\" && exit 1"
  },
  "dependencies": {
    "express": "^4.18.0"
  }
}
EOF

cat > README.md << 'EOF'
# Demo Application

This is a sample application for demonstrating Codestral capabilities.

## Features

- Express.js server
- Basic routing
- TODO items for improvement

## Usage

```bash
npm install
npm start
```
EOF

echo "📝 Created sample files:"
echo "   - app.js (Express server with TODOs)"
echo "   - package.json (Node.js project)"
echo "   - README.md (Documentation)"
echo ""

# Function to send commands to Codestral
send_to_codestral() {
    local command="$1"
    local description="$2"
    
    echo "🤖 $description"
    echo "   Command: $command"
    echo ""
    
    # In a real scenario, you would pipe this to codestral
    # For demo purposes, we'll just show what would be sent
    echo "   → This would be sent to Codestral:"
    echo "   $command"
    echo ""
    
    # Simulate processing time
    sleep 1
}

echo "🎯 Demo Workflow Steps:"
echo ""

# Step 1: Basic file analysis
send_to_codestral \
    "Can you analyze @app.js and tell me what this application does?" \
    "Step 1: Analyze the main application file"

# Step 2: Find TODOs
send_to_codestral \
    "/search \"TODO\" --type js" \
    "Step 2: Search for TODO items in the codebase"

# Step 3: Security review
send_to_codestral \
    "Please review @app.js for security issues and suggest improvements" \
    "Step 3: Security analysis and recommendations"

# Step 4: Add authentication
send_to_codestral \
    "Add JWT authentication to the /admin endpoint in @app.js" \
    "Step 4: Implement authentication (would require approval)"

# Step 5: Generate tests
send_to_codestral \
    "Create comprehensive unit tests for @app.js using Jest" \
    "Step 5: Generate test suite"

# Step 6: Improve documentation
send_to_codestral \
    "Enhance @README.md with better documentation, installation steps, and API endpoints" \
    "Step 6: Improve project documentation"

# Step 7: Add error handling
send_to_codestral \
    "Add proper error handling and logging to @app.js" \
    "Step 7: Implement error handling"

# Step 8: Create deployment configuration
send_to_codestral \
    "Create Docker configuration and deployment scripts for this application" \
    "Step 8: Setup deployment configuration"

echo "✨ Demo workflow complete!"
echo ""
echo "📋 What this demo showed:"
echo "   ✓ File analysis and code review"
echo "   ✓ Codebase search capabilities"
echo "   ✓ Security vulnerability detection"
echo "   ✓ Automated code improvements"
echo "   ✓ Test generation"
echo "   ✓ Documentation enhancement"
echo "   ✓ Error handling implementation"
echo "   ✓ Deployment configuration"
echo ""
echo "🚀 To run this workflow with real Codestral:"
echo "   1. Start Codestral: codestral"
echo "   2. Navigate to this directory: cd $PWD"
echo "   3. Run each command manually or use /mode autonomous"
echo "   4. Watch as AI autonomously improves your code!"
echo ""
echo "💡 Try these autonomy modes:"
echo "   /mode safe       - Requires approval for file changes"
echo "   /mode autonomous - Auto-approves file operations"
echo "   /mode full       - Maximum autonomy with safety checks"
echo ""

# Create a summary file
cat > DEMO_SUMMARY.md << EOF
# Codestral Demo Summary

## Demo Project: $DEMO_DIR

This demo showcased Codestral's agentic capabilities:

### Files Created
- \`app.js\` - Sample Express.js application with security issues and TODOs
- \`package.json\` - Node.js project configuration
- \`README.md\` - Basic project documentation

### Workflow Demonstrated
1. **Code Analysis** - AI reads and understands application structure
2. **Search Capabilities** - Find TODOs, security issues, patterns
3. **Security Review** - Identify vulnerabilities and suggest fixes
4. **Automated Improvements** - Add authentication, error handling
5. **Test Generation** - Create comprehensive test suites
6. **Documentation** - Enhance README and add API docs
7. **DevOps Setup** - Docker configuration and deployment scripts

### Key Features Shown
- File mention system (@filename)
- Autonomous tool execution
- Multi-step problem solving
- Code generation and modification
- Security analysis
- Documentation generation

### Next Steps
1. Start Codestral in this directory
2. Try the commands from the demo script
3. Experiment with different autonomy modes
4. Build your own projects with AI assistance

Generated on: $(date)
EOF

echo "📄 Created DEMO_SUMMARY.md with complete workflow details"
echo ""
echo "🎉 Demo setup complete! Happy coding with Codestral!"